DO $$
DECLARE
  rec        RECORD;
  v_job_id   UUID;
  v_imported INT := 0;
  v_dup      INT := 0;
  v_no_job   INT := 0;
BEGIN
  FOR rec IN SELECT * FROM _sched_staging LOOP
    IF EXISTS (SELECT 1 FROM schedule_items WHERE bt_schedule_id = rec.bt_schedule_id) THEN
      v_dup := v_dup + 1; CONTINUE;
    END IF;
    SELECT id INTO v_job_id FROM jobs WHERE bt_job_id = rec.bt_job_id LIMIT 1;
    IF v_job_id IS NULL THEN v_no_job := v_no_job + 1; CONTINUE; END IF;

    INSERT INTO schedule_items (
      job_id, title, notes, start_date, end_date, work_days,
      scheduling_type, progress, reminder, display_color, assignee_color, assignees,
      crew_id, sub_id, include_saturday, include_sunday, needs_crew, work_order_ids,
      bt_schedule_id, completed_at, completed_by_name
    ) VALUES (
      v_job_id, rec.title, rec.notes,
      COALESCE(rec.start_date, CURRENT_DATE),
      COALESCE(rec.end_date,   COALESCE(rec.start_date, CURRENT_DATE)),
      GREATEST(1, COALESCE(rec.work_days, 1)),
      'crew_type', COALESCE(rec.progress, 0), 'None',
      '#15803d', NULL, COALESCE(rec.assignees, ''),
      NULL, NULL, FALSE, FALSE, FALSE, ARRAY[]::uuid[],
      rec.bt_schedule_id, rec.completed_at, rec.completed_by
    );

    v_imported := v_imported + 1;
  END LOOP;

  RAISE NOTICE 'Batch 2 of 5 — Imported: %, Already imported: %, No matching job: %',
    v_imported, v_dup, v_no_job;
END $$;

COMMIT;
